    def bulk_create_entities(
        self,
        names: list[str],
        default_policies: list[str] | None = None,
    ) -> list[Entity]:
        results: list[Entity] = []
        for name in names:
            try:
                entity = self._store.create_entity(name, policies=default_policies)
                results.append(entity)
            except VaultError:
                continue
        return results

