"""Authentication backends and helpers for VaultKey."""
from __future__ import annotations

import hashlib
import time
from dataclasses import dataclass, field
from typing import Any, Protocol

from vaultkey.access.tokens import TokenStore
from vaultkey.crypto.random import (
    constant_time_compare,
    generate_id,
    generate_salt,
    generate_token,
)
from vaultkey.utils.errors import AuthenticationError, TokenError


def _now(value: float | None = None) -> float:
    return time.time() if value is None else value


def _require(value: str | None, name: str) -> str:
    if value is None or value == "":
        raise AuthenticationError(f"missing {name}", details={"field": name})
    return value


def _normalize_fingerprint(fingerprint: str) -> str:
    return "".join(ch for ch in fingerprint.lower() if ch not in ":- \t\r\n")


@dataclass(frozen=True)
class AuthResult:
    """Successful authentication result returned by auth backends."""
    backend: str
    subject: str
    policies: list[str] = field(default_factory=list)
    metadata: dict[str, str] = field(default_factory=dict)
    ttl: float = 3600.0
    entity_id: str | None = None
    token_id: str | None = None
    accessor: str | None = None
    renewable: bool = True

    def to_dict(self) -> dict[str, Any]:
