            "entity_id": self.entity_id,
            "token_id": self.token_id,
            "accessor": self.accessor,
            "renewable": self.renewable,
        }


class AuthBackend(Protocol):
    """Common interface implemented by auth backends."""
    name: str
    enabled: bool

