class UserpassAuthBackend(BaseAuthBackend):
    """Username/password authentication using salted PBKDF2 hashes."""

    name = "userpass"

    def __init__(self, enabled: bool = True, iterations: int = 120_000) -> None:
        super().__init__(enabled=enabled)
        self.iterations = iterations
        self._users: dict[str, UserpassUser] = {}

    def create_user(
        self,
        username: str,
        password: str,
        policies: list[str] | None = None,
        metadata: dict[str, str] | None = None,
        ttl: float = 3600.0,
        disabled: bool = False,
    ) -> UserpassUser:
        if not username:
            raise AuthenticationError("missing username", details={"field": "username"})
        if not password:
            raise AuthenticationError("missing password", details={"field": "password"})
        if username in self._users:
            raise AuthenticationError("user already exists", details={"username": username})

        salt = generate_salt(16)
        user = UserpassUser(
            username=username,
            password_hash=self._hash_password(password, salt, self.iterations),
            salt=salt,
            iterations=self.iterations,
            policies=list(policies or []),
            metadata=dict(metadata or {}),
            ttl=ttl,
            disabled=disabled,
        )
        self._users[username] = user
        return user

    def authenticate(self, **credentials: Any) -> AuthResult:
        self._ensure_enabled()
        username = _require(credentials.get("username"), "username")
        password = _require(credentials.get("password"), "password")

        user = self._users.get(username)
        if user is None or user.disabled:
            raise AuthenticationError("invalid credentials", details={"backend": self.name})

        candidate = self._hash_password(password, user.salt, user.iterations)
        if not constant_time_compare(candidate, user.password_hash):
            raise AuthenticationError("invalid credentials", details={"backend": self.name})

        return AuthResult(
            backend=self.name,
            subject=username,
            policies=list(user.policies),
            metadata=dict(user.metadata),
            ttl=user.ttl,
        )

    def set_password(self, username: str, password: str) -> None:
        user = self._get_user(username)
        if not password:
            raise AuthenticationError("missing password", details={"field": "password"})
        salt = generate_salt(16)
        user.password_hash = self._hash_password(password, salt, self.iterations)
        user.salt = salt
        user.iterations = self.iterations
        user.updated_at = time.time()

    def disable_user(self, username: str) -> bool:
        user = self._users.get(username)
        if user is None:
            return False
        user.disabled = True
        user.updated_at = time.time()
        return True

    def enable_user(self, username: str) -> bool:
        user = self._users.get(username)
        if user is None:
            return False
        user.disabled = False
        user.updated_at = time.time()
        return True

    def delete_user(self, username: str) -> bool:
        return self._users.pop(username, None) is not None

    def get_user(self, username: str) -> UserpassUser | None:
        return self._users.get(username)

    def list_users(self) -> list[str]:
        return sorted(self._users)

    def _get_user(self, username: str) -> UserpassUser:
        user = self._users.get(username)
        if user is None:
            raise AuthenticationError("user not found", details={"username": username})
        return user

    @staticmethod
    def _hash_password(password: str, salt: bytes, iterations: int) -> bytes:
        return hashlib.pbkdf2_hmac("sha256", password.encode("utf-8"), salt, iterations)


@dataclass
class AppRoleSecretID:
    """Generated secret ID bound to an AppRole."""
    secret_id: str
    created_at: float = field(default_factory=time.time)
    ttl: float = 0.0
    num_uses: int = 0
    uses_remaining: int = 0
    metadata: dict[str, str] = field(default_factory=dict)

    def __post_init__(self) -> None:
        if self.num_uses > 0 and self.uses_remaining == 0:
            self.uses_remaining = self.num_uses

    def is_expired(self, now: float | None = None) -> bool:
        if self.ttl <= 0:
            return False
        return _now(now) >= self.created_at + self.ttl

    def use(self) -> None:
        if self.num_uses > 0:
            if self.uses_remaining <= 0:
                raise AuthenticationError("invalid credentials", details={"backend": "approle"})
            self.uses_remaining -= 1

    def to_dict(self) -> dict[str, Any]:
        return {
            "secret_id": self.secret_id[:8] + "...",
            "ttl": self.ttl,
            "num_uses": self.num_uses,
            "uses_remaining": self.uses_remaining,
            "metadata": dict(self.metadata),
        }


