class AppRoleAuthBackend(BaseAuthBackend):
    """AppRole authentication with generated role IDs and secret IDs."""

    name = "approle"

    def __init__(self, enabled: bool = True) -> None:
        super().__init__(enabled=enabled)
        self._roles: dict[str, AppRole] = {}
        self._role_id_index: dict[str, str] = {}

    def create_role(
        self,
        role_name: str,
        policies: list[str] | None = None,
        metadata: dict[str, str] | None = None,
        ttl: float = 3600.0,
        bind_secret_id: bool = True,
        disabled: bool = False,
    ) -> AppRole:
        if not role_name:
            raise AuthenticationError("missing role name", details={"field": "role_name"})
        if role_name in self._roles:
            raise AuthenticationError("role already exists", details={"role_name": role_name})
        role_id = generate_id("role", 20)
        role = AppRole(
            role_name=role_name,
            role_id=role_id,
            policies=list(policies or []),
            metadata=dict(metadata or {}),
            ttl=ttl,
            bind_secret_id=bind_secret_id,
            disabled=disabled,
        )
        self._roles[role_name] = role
        self._role_id_index[role_id] = role_name
        return role

    def generate_secret_id(
        self,
        role_name: str,
        ttl: float = 0.0,
        num_uses: int = 0,
        metadata: dict[str, str] | None = None,
    ) -> AppRoleSecretID:
        role = self._get_role(role_name)
        secret = AppRoleSecretID(
            secret_id=generate_token(32),
            ttl=ttl,
            num_uses=num_uses,
            metadata=dict(metadata or {}),
        )
        role.secret_ids[secret.secret_id] = secret
        return secret

    def authenticate(self, **credentials: Any) -> AuthResult:
        self._ensure_enabled()
        role_id = _require(credentials.get("role_id"), "role_id")
        role_name = self._role_id_index.get(role_id)
        if role_name is None:
            raise AuthenticationError("invalid credentials", details={"backend": self.name})
        role = self._roles[role_name]
        if role.disabled:
            raise AuthenticationError("invalid credentials", details={"backend": self.name})

        metadata = dict(role.metadata)
        if role.bind_secret_id:
            secret_id = _require(credentials.get("secret_id"), "secret_id")
            secret = self._find_secret(role, secret_id, credentials.get("now"))
            secret.use()
            metadata.update(secret.metadata)

        return AuthResult(
            backend=self.name,
            subject=role.role_name,
            policies=list(role.policies),
            metadata=metadata,
            ttl=role.ttl,
        )

    def delete_role(self, role_name: str) -> bool:
        role = self._roles.pop(role_name, None)
        if role is None:
            return False
        self._role_id_index.pop(role.role_id, None)
        return True

    def get_role(self, role_name: str) -> AppRole | None:
        return self._roles.get(role_name)

    def list_roles(self) -> list[str]:
        return sorted(self._roles)

    def list_role_ids(self) -> list[str]:
        return sorted(self._role_id_index)

    def disable_role(self, role_name: str) -> bool:
        role = self._roles.get(role_name)
        if role is None:
            return False
        role.disabled = True
        return True

    def enable_role(self, role_name: str) -> bool:
        role = self._roles.get(role_name)
        if role is None:
            return False
        role.disabled = False
        return True

    def _get_role(self, role_name: str) -> AppRole:
        role = self._roles.get(role_name)
        if role is None:
            raise AuthenticationError("role not found", details={"role_name": role_name})
        return role

    def _find_secret(
        self,
        role: AppRole,
        secret_id: str,
        now: float | None = None,
    ) -> AppRoleSecretID:
        secret_bytes = secret_id.encode("utf-8")
        for stored in role.secret_ids.values():
            stored_bytes = stored.secret_id.encode("utf-8")
            if constant_time_compare(secret_bytes, stored_bytes) and not stored.is_expired(now):
                return stored
        raise AuthenticationError("invalid credentials", details={"backend": self.name})


