class CertificateAuthBackend(BaseAuthBackend):
    """Certificate authentication by configured fingerprint."""

    name = "certificate"

    def __init__(self, enabled: bool = True) -> None:
        super().__init__(enabled=enabled)
        self._certificates: dict[str, CertificateIdentity] = {}

    def register_certificate(
        self,
        name: str,
        fingerprint: str,
        policies: list[str] | None = None,
        metadata: dict[str, str] | None = None,
        ttl: float = 3600.0,
        disabled: bool = False,
    ) -> CertificateIdentity:
