        if not normalized:
            raise AuthenticationError("missing fingerprint", details={"field": "fingerprint"})
        if name in self._certificates:
            raise AuthenticationError("certificate already exists", details={"name": name})
        if self._find_by_fingerprint(normalized) is not None:
            raise AuthenticationError("fingerprint already exists", details={"name": name})

        cert = CertificateIdentity(
            name=name,
            fingerprint=normalized,
            policies=list(policies or []),
            metadata=dict(metadata or {}),
            ttl=ttl,
            disabled=disabled,
        )
        self._certificates[name] = cert
        return cert

