        self._ensure_enabled()
        raw_fingerprint = credentials.get("fingerprint", credentials.get("cert_fingerprint"))
        fingerprint = _normalize_fingerprint(_require(raw_fingerprint, "fingerprint"))
        cert = self._find_by_fingerprint(fingerprint)
        if cert is None or cert.disabled:
            raise AuthenticationError("invalid credentials", details={"backend": self.name})
        return AuthResult(
            backend=self.name,
            subject=cert.name,
            policies=list(cert.policies),
            metadata=dict(cert.metadata),
            ttl=cert.ttl,
        )

    def get_certificate(self, name: str) -> CertificateIdentity | None:
        return self._certificates.get(name)

    def delete_certificate(self, name: str) -> bool:
        return self._certificates.pop(name, None) is not None

    def list_certificates(self) -> list[str]:
        return sorted(self._certificates)

    def disable_certificate(self, name: str) -> bool:
        cert = self._certificates.get(name)
        if cert is None:
            return False
        cert.disabled = True
        return True

    def enable_certificate(self, name: str) -> bool:
        cert = self._certificates.get(name)
        if cert is None:
            return False
        cert.disabled = False
        return True

    def _find_by_fingerprint(self, fingerprint: str) -> CertificateIdentity | None:
        fingerprint_bytes = fingerprint.encode("utf-8")
        for cert in self._certificates.values():
            stored = cert.fingerprint.encode("utf-8")
            if constant_time_compare(fingerprint_bytes, stored):
                return cert
        return None


class TokenAuthBackend(BaseAuthBackend):
    """Authentication backend for validating already-issued tokens."""

    name = "token"

    def __init__(self, token_store: TokenStore, enabled: bool = True) -> None:
        super().__init__(enabled=enabled)
        self._token_store = token_store

    def authenticate(self, **credentials: Any) -> AuthResult:
        self._ensure_enabled()
        token_id = credentials.get("token", credentials.get("token_id"))
        token_id = _require(token_id, "token")
        try:
            token = self._token_store.lookup(token_id)
            token.use()
        except TokenError as exc:
            raise AuthenticationError("invalid token", details={"backend": self.name}) from exc

        subject = token.entity_id or token.accessor
        return AuthResult(
            backend=self.name,
            subject=subject,
            policies=list(token.policies),
            metadata=dict(token.metadata),
            ttl=token.remaining_ttl,
            entity_id=token.entity_id,
            token_id=token.token_id,
            accessor=token.accessor,
            renewable=token.renewable,
        )


class AuthManager:
    """Registers auth backends and dispatches authentication requests."""

    def __init__(self) -> None:
        self._backends: dict[str, AuthBackend] = {}

    def register_backend(self, name: str, backend: AuthBackend) -> None:
        if not name:
            raise AuthenticationError("missing backend name", details={"field": "name"})
        self._backends[name] = backend

    def register(self, backend: AuthBackend, name: str | None = None) -> None:
        self.register_backend(name or backend.name, backend)

    def authenticate(self, backend_name: str, **credentials: Any) -> AuthResult:
        backend = self._backends.get(backend_name)
        if backend is None:
            raise AuthenticationError(
                f"unknown auth backend: {backend_name}",
                details={"backend": backend_name},
            )
        if not backend.enabled:
            raise AuthenticationError(
                f"auth backend disabled: {backend_name}",
                details={"backend": backend_name},
            )
        return backend.authenticate(**credentials)

    def get_backend(self, name: str) -> AuthBackend | None:
        return self._backends.get(name)

    def unregister_backend(self, name: str) -> bool:
        return self._backends.pop(name, None) is not None

    def enable_backend(self, name: str) -> None:
        backend = self._get_backend(name)
        if hasattr(backend, "enable"):
            backend.enable()
        else:
            backend.enabled = True

    def disable_backend(self, name: str) -> None:
        backend = self._get_backend(name)
        if hasattr(backend, "disable"):
            backend.disable()
        else:
            backend.enabled = False

    def list_backends(self) -> list[str]:
        return sorted(self._backends)

    def _get_backend(self, name: str) -> AuthBackend:
        backend = self._backends.get(name)
        if backend is None:
            raise AuthenticationError(f"unknown auth backend: {name}", details={"backend": name})
        return backend


class AuthRateLimiter:
    """Tracks failed auth attempts with fixed-window lockouts."""

    def __init__(self, max_attempts: int = 5, window: float = 60.0, lockout: float = 300.0) -> None:
        if max_attempts <= 0:
            raise ValueError("max_attempts must be positive")
        self.max_attempts = max_attempts
        self.window = window
        self.lockout = lockout
        self._failures: dict[str, list[float]] = {}
        self._locked_until: dict[str, float] = {}

    def record_attempt(self, key: str, success: bool, now: float | None = None) -> bool:
        current = _now(now)
        if success:
            self.reset(key)
            return False

        failures = self._recent_failures(key, current)
        failures.append(current)
        self._failures[key] = failures
        if len(failures) >= self.max_attempts:
            self._locked_until[key] = current + self.lockout
            return True
        return False

    def is_limited(self, key: str, now: float | None = None) -> bool:
        current = _now(now)
        locked_until = self._locked_until.get(key, 0.0)
        if locked_until > current:
            return True
        self._locked_until.pop(key, None)
        self._failures[key] = self._recent_failures(key, current)
        return False

    def retry_after(self, key: str, now: float | None = None) -> float:
        current = _now(now)
        return max(0.0, self._locked_until.get(key, 0.0) - current)

    def failure_count(self, key: str, now: float | None = None) -> int:
        current = _now(now)
        failures = self._recent_failures(key, current)
        self._failures[key] = failures
        return len(failures)

    def reset(self, key: str) -> None:
        self._failures.pop(key, None)
        self._locked_until.pop(key, None)

    def _recent_failures(self, key: str, now: float) -> list[float]:
        cutoff = now - self.window
        return [ts for ts in self._failures.get(key, []) if ts >= cutoff]


@dataclass
class AuthSession:
    """Tracked authenticated session."""
    session_id: str
    backend: str
    subject: str
    policies: list[str] = field(default_factory=list)
    metadata: dict[str, str] = field(default_factory=dict)
    created_at: float = field(default_factory=time.time)
    expires_at: float = 0.0
    last_active: float = field(default_factory=time.time)
    revoked: bool = False

    def is_expired(self, now: float | None = None) -> bool:
        return self.expires_at > 0 and _now(now) >= self.expires_at

    def is_active(self, now: float | None = None) -> bool:
        return not self.revoked and not self.is_expired(now)

    def to_dict(self) -> dict[str, Any]:
        return {
            "session_id": self.session_id,
            "backend": self.backend,
            "subject": self.subject,
            "policies": list(self.policies),
            "metadata": dict(self.metadata),
            "created_at": self.created_at,
            "expires_at": self.expires_at,
            "last_active": self.last_active,
            "revoked": self.revoked,
        }


class AuthSessionStore:
    """In-memory authenticated session tracker."""

    def __init__(self) -> None:
        self._sessions: dict[str, AuthSession] = {}

    def create_session(
        self,
        result: AuthResult,
        ttl: float | None = None,
        now: float | None = None,
    ) -> AuthSession:
        current = _now(now)
        session_ttl = result.ttl if ttl is None else ttl
        expires_at = 0.0 if session_ttl <= 0 else current + session_ttl
        session = AuthSession(
            session_id=generate_id("sess"),
            backend=result.backend,
            subject=result.subject,
            policies=list(result.policies),
            metadata=dict(result.metadata),
            created_at=current,
            expires_at=expires_at,
            last_active=current,
        )
        self._sessions[session.session_id] = session
        return session

    def get_session(self, session_id: str, now: float | None = None) -> AuthSession | None:
        session = self._sessions.get(session_id)
        if session is None or not session.is_active(now):
            return None
        return session

    def touch_session(self, session_id: str, now: float | None = None) -> bool:
        session = self.get_session(session_id, now=now)
        if session is None:
            return False
        session.last_active = _now(now)
        return True

    def revoke_session(self, session_id: str) -> bool:
        session = self._sessions.get(session_id)
        if session is None:
            return False
        session.revoked = True
        return True

    def list_sessions(
        self,
        subject: str | None = None,
        active_only: bool = True,
        now: float | None = None,
    ) -> list[AuthSession]:
        sessions = list(self._sessions.values())
        if subject is not None:
            sessions = [session for session in sessions if session.subject == subject]
        if active_only:
            sessions = [session for session in sessions if session.is_active(now)]
        return sorted(sessions, key=lambda session: session.session_id)

    def count(self, active_only: bool = True, now: float | None = None) -> int:
        return len(self.list_sessions(active_only=active_only, now=now))


@dataclass
class MFAChallenge:
    """One-time MFA challenge."""
    challenge_id: str
    subject: str
    method: str
    code_hash: bytes
    salt: bytes
    created_at: float = field(default_factory=time.time)
    expires_at: float = 0.0
    attempts_remaining: int = 3
    metadata: dict[str, str] = field(default_factory=dict)
    verified: bool = False

    def is_expired(self, now: float | None = None) -> bool:
        return self.expires_at > 0 and _now(now) >= self.expires_at

    def to_dict(self) -> dict[str, Any]:
        return {
            "challenge_id": self.challenge_id,
            "subject": self.subject,
            "method": self.method,
            "created_at": self.created_at,
            "expires_at": self.expires_at,
            "attempts_remaining": self.attempts_remaining,
            "metadata": dict(self.metadata),
            "verified": self.verified,
        }


class MFAChallengeStore:
    """Creates and verifies deterministic in-memory MFA challenges."""

    def __init__(self, ttl: float = 300.0, max_attempts: int = 3) -> None:
        self.ttl = ttl
        self.max_attempts = max_attempts
        self._challenges: dict[str, MFAChallenge] = {}

    def create_challenge(
        self,
        subject: str,
        method: str = "totp",
        code: str | None = None,
        metadata: dict[str, str] | None = None,
        now: float | None = None,
    ) -> tuple[MFAChallenge, str]:
        if not subject:
            raise AuthenticationError("missing subject", details={"field": "subject"})
        current = _now(now)
        verification_code = code or generate_token(6)
        salt = generate_salt(16)
        challenge = MFAChallenge(
            challenge_id=generate_id("mfa"),
            subject=subject,
            method=method,
            code_hash=self._hash_code(verification_code, salt),
            salt=salt,
            created_at=current,
            expires_at=current + self.ttl if self.ttl > 0 else 0.0,
            attempts_remaining=self.max_attempts,
            metadata=dict(metadata or {}),
        )
        self._challenges[challenge.challenge_id] = challenge
        return challenge, verification_code

    def verify(self, challenge_id: str, code: str, now: float | None = None) -> bool:
        challenge = self._challenges.get(challenge_id)
        if challenge is None:
            raise AuthenticationError("MFA challenge not found", details={"challenge_id": challenge_id})
        if challenge.verified:
            return True
        if challenge.is_expired(now):
            raise AuthenticationError("MFA challenge expired", details={"challenge_id": challenge_id})
        if challenge.attempts_remaining <= 0:
            raise AuthenticationError("MFA challenge exhausted", details={"challenge_id": challenge_id})

        candidate = self._hash_code(_require(code, "code"), challenge.salt)
        if not constant_time_compare(candidate, challenge.code_hash):
            challenge.attempts_remaining -= 1
            raise AuthenticationError("invalid MFA code", details={"challenge_id": challenge_id})

        challenge.verified = True
        return True

    def get_challenge(self, challenge_id: str) -> MFAChallenge | None:
        return self._challenges.get(challenge_id)

    def list_challenges(self, subject: str | None = None) -> list[MFAChallenge]:
        challenges = list(self._challenges.values())
        if subject is not None:
            challenges = [challenge for challenge in challenges if challenge.subject == subject]
        return sorted(challenges, key=lambda challenge: challenge.challenge_id)

    def delete_challenge(self, challenge_id: str) -> bool:
        return self._challenges.pop(challenge_id, None) is not None

    @staticmethod
    def _hash_code(code: str, salt: bytes) -> bytes:
        return hashlib.pbkdf2_hmac("sha256", code.encode("utf-8"), salt, 20_000)


@dataclass
class AuthEvent:
    """Auth event log entry."""
    event_id: str
    backend: str
    subject: str = ""
    success: bool = True
    timestamp: float = field(default_factory=time.time)
    error: str = ""
    metadata: dict[str, str] = field(default_factory=dict)

    def to_dict(self) -> dict[str, Any]:
        return {
            "event_id": self.event_id,
            "backend": self.backend,
            "subject": self.subject,
            "success": self.success,
            "timestamp": self.timestamp,
            "error": self.error,
            "metadata": dict(self.metadata),
        }


class AuthEventLog:
    """Bounded in-memory auth event log."""

    def __init__(self, max_entries: int = 10000) -> None:
        self._entries: list[AuthEvent] = []
        self._max_entries = max_entries

    def log(
        self,
        backend: str,
        subject: str = "",
        success: bool = True,
        error: str = "",
        metadata: dict[str, str] | None = None,
        now: float | None = None,
    ) -> AuthEvent:
        entry = AuthEvent(
            event_id=generate_id("auth"),
            backend=backend,
            subject=subject,
            success=success,
            timestamp=_now(now),
            error=error,
            metadata=dict(metadata or {}),
        )
        if len(self._entries) >= self._max_entries:
            self._entries.pop(0)
        self._entries.append(entry)
        return entry

    def get_events(
        self,
        backend: str | None = None,
        subject: str | None = None,
        success: bool | None = None,
        since: float = 0.0,
    ) -> list[AuthEvent]:
        entries = self._entries
        if backend is not None:
            entries = [entry for entry in entries if entry.backend == backend]
        if subject is not None:
            entries = [entry for entry in entries if entry.subject == subject]
        if success is not None:
            entries = [entry for entry in entries if entry.success == success]
        if since:
            entries = [entry for entry in entries if entry.timestamp >= since]
        return list(entries)

    @property
    def total_entries(self) -> int:
        return len(self._entries)

    def clear(self) -> None:
        self._entries.clear()


@dataclass(frozen=True)
class AuthConfigValidationResult:
    """Result returned by auth configuration validation."""
    valid: bool
    errors: list[str] = field(default_factory=list)
    warnings: list[str] = field(default_factory=list)

    def to_dict(self) -> dict[str, Any]:
        return {
            "valid": self.valid,
            "errors": list(self.errors),
            "warnings": list(self.warnings),
        }


def validate_auth_config(config: dict[str, Any]) -> AuthConfigValidationResult:
    """Validate a simple auth configuration dictionary."""
    errors: list[str] = []
    warnings: list[str] = []
    known_types = {"userpass", "approle", "certificate", "token"}

    if not isinstance(config, dict):
        return AuthConfigValidationResult(False, ["config must be a dictionary"], [])

    backends = config.get("backends", {})
    if not isinstance(backends, dict):
        errors.append("backends must be a dictionary")
    elif not backends:
        warnings.append("no auth backends configured")
    else:
        for name, backend_config in backends.items():
            if not isinstance(name, str) or not name:
                errors.append("backend names must be non-empty strings")
                continue
            if not isinstance(backend_config, dict):
                errors.append(f"backend {name} must be a dictionary")
                continue
            backend_type = backend_config.get("type", name)
            if backend_type not in known_types:
                errors.append(f"backend {name} has unknown type: {backend_type}")
            enabled = backend_config.get("enabled", True)
            if not isinstance(enabled, bool):
                errors.append(f"backend {name} enabled must be a boolean")
            default_ttl = backend_config.get("default_ttl", 3600.0)
            if not isinstance(default_ttl, int | float) or default_ttl < 0:
                errors.append(f"backend {name} default_ttl must be a non-negative number")
            if backend_type == "userpass":
                iterations = backend_config.get("iterations", 120_000)
                if not isinstance(iterations, int) or iterations <= 0:
                    errors.append(f"backend {name} iterations must be a positive integer")

    return AuthConfigValidationResult(valid=not errors, errors=errors, warnings=warnings)


